# 023-quasi_geo-estimation.R
# Generated by behavior-preserving split of quasi_geo_test.R.

qgt_estimate_event <- function(dt,
                               event,
                               date_col,
                               dep_var_col,
                               raw_dep_col = NULL,
                               geo_col,
                               media_col,
                               raw_media_col = media_col,
                               spend_col = media_col,
                               all_media_cols,
                               all_raw_media_cols = NULL,
                               all_spend_cols = NULL,
                               control_cols = character(),
                               pre_weeks = 8L,
                               post_weeks = 4L,
                               min_volume = 1e-8,
                               donor_contamination_pct = 0.20,
                               other_media_contamination_pct = 0.25,
                               min_donors = 3L,
                               mde_alpha = 0.05,
                               mde_power = 0.80,
                               lambda_grid = 10 ^ seq(-4, 2, length.out = 20)) {
  e <- event[1]
  treat_geo <- as.character(e$geo)
  dd <- copy(dt)
  dd[, date__ := get(date_col)]
  dd[, geo__ := as.character(get(geo_col))]
  dd[, y__ := qgt_num(get(dep_var_col))]
  if (!is.null(raw_dep_col) && raw_dep_col %in% names(dd)) {
    dd[, y_raw__ := qgt_num(get(raw_dep_col))]
  } else {
    dd[, y_raw__ := y__]
  }
  pre_idx <- dt[[date_col]] >= e$pre_start & dt[[date_col]] <= e$pre_end
  post_idx <- dt[[date_col]] >= e$post_start & dt[[date_col]] <= e$post_end
  event_dates <- dt[[date_col]] >= e$event_start & dt[[date_col]] <= e$event_end
  if (sum(pre_idx) < pre_weeks || sum(post_idx) < post_weeks) {
    return(qgt_event_not_estimable(event, "insufficient_pre_or_post_window"))
  }

  donor_geos <- setdiff(unique(as.character(dt[[geo_col]])), treat_geo)
  if (!length(donor_geos)) return(qgt_event_not_estimable(event, "no_candidate_donor_geos"))
  med <- media_col
  raw_med <- if (!is.null(raw_media_col) && raw_media_col %in% names(dt)) raw_media_col else med
  donor_materiality <- max(min_volume, 0.05 * qgt_positive_scale(dt[[raw_med]], floor = min_volume))
  contamination <- dt[as.character(get(geo_col)) %in% donor_geos & event_dates, .(
    donor_post_media = mean(pmax(qgt_num(get(raw_med)), 0), na.rm = TRUE)
  ), by = geo_col]
  pre_base <- dt[as.character(get(geo_col)) %in% donor_geos & pre_idx, .(
    donor_pre_media = mean(pmax(qgt_num(get(raw_med)), 0), na.rm = TRUE)
  ), by = geo_col]
  contamination <- pre_base[contamination, on = geo_col]
  contamination[, donor_change_class := qgt_change_class(donor_pre_media, donor_post_media, donor_contamination_pct, near_zero = min_volume, material = donor_materiality)]
  contamination[, donor_pct_change := fifelse(
    is.finite(donor_pre_media) & donor_pre_media > 1e-8,
    (donor_post_media - donor_pre_media) / donor_pre_media,
    fifelse(donor_change_class == "turn_on", Inf, fifelse(donor_change_class == "turn_off", -Inf, 0))
  )]
  clean_donor_candidates <- contamination[
    is.na(donor_pct_change) |
      (abs(donor_pct_change) < donor_contamination_pct & !donor_change_class %in% c("turn_on", "turn_off")),
    as.character(get(geo_col))
  ]
  clean_donor_candidates <- unique(clean_donor_candidates[!is.na(clean_donor_candidates) & nzchar(clean_donor_candidates)])
  unaffected_donor_n <- length(clean_donor_candidates)
  donor_contaminated_geo_n <- max(length(donor_geos) - unaffected_donor_n, 0L)
  no_unaffected_donor_geos <- length(donor_geos) > 0L && unaffected_donor_n == 0L
  clean_donors <- clean_donor_candidates
  donor_contamination_max <- if (nrow(contamination) && any(contamination$donor_change_class %in% c("turn_on", "turn_off"), na.rm = TRUE)) {
    Inf
  } else if (nrow(contamination) && any(is.finite(contamination$donor_pct_change))) {
    max(abs(contamination$donor_pct_change[is.finite(contamination$donor_pct_change)]), na.rm = TRUE)
  } else {
    NA_real_
  }
  donor_contamination_flag <- length(clean_donors) < min_donors
  if (length(clean_donors) < min_donors) {
    clean_donors <- donor_geos
  }

  pre_wide <- dcast(dd[geo__ %in% c(treat_geo, clean_donors) & pre_idx],
                    date__ ~ geo__, value.var = "y__")
  if (!treat_geo %in% names(pre_wide)) return(qgt_event_not_estimable(event, "treated_geo_missing_pre_period"))
  donor_cols <- intersect(clean_donors, names(pre_wide))
  if (!length(donor_cols)) return(qgt_event_not_estimable(event, "no_donor_data_in_pre_period"))
  weights <- qgt_ridge_synth_weights(pre_wide[[treat_geo]], pre_wide[, ..donor_cols], lambda_grid = lambda_grid, simplex = TRUE)
  ridge_lambda <- attr(weights, "lambda") %||% NA_real_
  ridge_lambda_cv_rmse <- attr(weights, "lambda_cv_rmse") %||% NA_real_
  ridge_lambda_selection_method <- attr(weights, "lambda_selection_method") %||% NA_character_
  ridge_lambda_cv_fold_n <- attr(weights, "lambda_cv_fold_n") %||% 0L
  ridge_retained_donor_n <- attr(weights, "retained_donor_n") %||% NA_integer_
  ridge_dropped_zero_variance_donor_n <- attr(weights, "dropped_zero_variance_donor_n") %||% NA_integer_
  synth_available <- !all(!is.finite(weights))
  if (isTRUE(synth_available)) names(weights) <- donor_cols

  full_wide <- dcast(dd[geo__ %in% c(treat_geo, donor_cols) & (pre_idx | post_idx)],
                     date__ ~ geo__, value.var = "y__")
  donor_cols <- donor_cols[donor_cols %in% names(full_wide)]
  if (!length(donor_cols)) return(qgt_event_not_estimable(event, "no_donor_data_in_pre_period"))
  if (isTRUE(synth_available)) {
    weights <- weights[donor_cols]
    weight_sum <- sum(weights, na.rm = TRUE)
    if (!is.finite(weight_sum) || weight_sum <= 1e-12) {
      synth_available <- FALSE
      weights <- stats::setNames(rep(NA_real_, length(donor_cols)), donor_cols)
    } else {
      weights <- weights / weight_sum
    }
  } else {
    weights <- stats::setNames(rep(NA_real_, length(donor_cols)), donor_cols)
  }
  if (isTRUE(synth_available)) {
    donor_pre_means <- vapply(donor_cols, function(cc) mean(pre_wide[[cc]], na.rm = TRUE), numeric(1))
    synth_intercept <- mean(pre_wide[[treat_geo]], na.rm = TRUE) - sum(weights * donor_pre_means, na.rm = TRUE)
    full_wide[, synthetic_control_y := synth_intercept + as.numeric(as.matrix(.SD) %*% weights), .SDcols = donor_cols]
  } else {
    synth_intercept <- NA_real_
    full_wide[, synthetic_control_y := NA_real_]
  }
  tbr_fit <- qgt_tbr_counterfactual(
    wide = full_wide,
    treat_col = treat_geo,
    donor_cols = donor_cols,
    pre_start = e$pre_start,
    pre_end = e$pre_end,
    post_start = e$post_start,
    post_end = e$post_end,
    min_pre_rows = max(4L, min(6L, pre_weeks))
  )
  full_wide[, tbr_y := if (isTRUE(tbr_fit$success)) tbr_fit$pred else NA_real_]
  sc_pre_fit_tmp <- full_wide[date__ >= e$pre_start & date__ <= e$pre_end]
  sc_ok_tmp <- is.finite(qgt_num(sc_pre_fit_tmp[[treat_geo]])) & is.finite(qgt_num(sc_pre_fit_tmp$synthetic_control_y))
  synthetic_control_pre_fit_score <- if (isTRUE(synth_available) && sum(sc_ok_tmp) >= 2L) {
    sc_rmse <- sqrt(mean((qgt_num(sc_pre_fit_tmp[[treat_geo]])[sc_ok_tmp] - qgt_num(sc_pre_fit_tmp$synthetic_control_y)[sc_ok_tmp]) ^ 2, na.rm = TRUE))
    sc_sd <- qgt_safe_sd(sc_pre_fit_tmp[[treat_geo]][sc_ok_tmp], floor = 1e-8)
    1 - qgt_clip(sc_rmse / sc_sd, 0, 1)
  } else {
    NA_real_
  }
  synth_strong <- isTRUE(synth_available) &&
    is.finite(synthetic_control_pre_fit_score) &&
    synthetic_control_pre_fit_score >= 0.60 &&
    length(donor_cols) >= min_donors &&
    !isTRUE(donor_contamination_flag)
  use_tbr <- isTRUE(tbr_fit$success) && (
    !isTRUE(synth_available) ||
      !isTRUE(synth_strong) ||
      (is.finite(tbr_fit$pre_fit_score) && is.finite(synthetic_control_pre_fit_score) &&
         tbr_fit$pre_fit_score >= synthetic_control_pre_fit_score + 0.10)
  )
  selected_counterfactual_method <- if (isTRUE(use_tbr)) tbr_fit$method else "ridge_synthetic_control"
  counterfactual_fallback_reason <- if (isTRUE(use_tbr)) {
    paste(c(
      if (!isTRUE(synth_available)) "synthetic_control_weights_failed" else character(),
      if (isTRUE(donor_contamination_flag)) "donor_contamination_or_shortage" else character(),
      if (length(donor_cols) < min_donors) "few_donors" else character(),
      if (is.finite(synthetic_control_pre_fit_score) && synthetic_control_pre_fit_score < 0.60) "weak_synthetic_pre_fit" else character(),
      if (is.finite(tbr_fit$pre_fit_score) && is.finite(synthetic_control_pre_fit_score) &&
          tbr_fit$pre_fit_score >= synthetic_control_pre_fit_score + 0.10) "tbr_pre_fit_better" else character()
    ), collapse = "|")
  } else {
    ""
  }
  full_wide[, synth_y := if (isTRUE(use_tbr)) tbr_y else synthetic_control_y]
  if (!any(is.finite(full_wide$synth_y))) return(qgt_event_not_estimable(event, "counterfactual_estimation_failed"))
  full_wide_raw <- dcast(dd[geo__ %in% c(treat_geo, donor_cols) & (pre_idx | post_idx)],
                         date__ ~ geo__, value.var = "y_raw__")
  raw_donor_cols <- donor_cols[donor_cols %in% names(full_wide_raw)]
  raw_weights <- weights[raw_donor_cols]
  raw_weight_sum <- sum(raw_weights, na.rm = TRUE)
  if (!isTRUE(synth_available) || !length(raw_donor_cols) || !is.finite(raw_weight_sum) || raw_weight_sum <= 1e-12 || !treat_geo %in% names(full_wide_raw)) {
    full_wide_raw[, synthetic_control_y_raw := NA_real_]
    raw_synth_intercept <- NA_real_
  } else {
    raw_weights <- raw_weights / raw_weight_sum
    pre_wide_raw <- full_wide_raw[date__ >= e$pre_start & date__ <= e$pre_end]
    raw_donor_pre_means <- vapply(raw_donor_cols, function(cc) mean(pre_wide_raw[[cc]], na.rm = TRUE), numeric(1))
    raw_synth_intercept <- mean(pre_wide_raw[[treat_geo]], na.rm = TRUE) - sum(raw_weights * raw_donor_pre_means, na.rm = TRUE)
    full_wide_raw[, synthetic_control_y_raw := raw_synth_intercept + as.numeric(as.matrix(.SD) %*% raw_weights), .SDcols = raw_donor_cols]
  }
  tbr_raw_fit <- qgt_tbr_counterfactual(
    wide = full_wide_raw,
    treat_col = treat_geo,
    donor_cols = raw_donor_cols,
    pre_start = e$pre_start,
    pre_end = e$pre_end,
    post_start = e$post_start,
    post_end = e$post_end,
    min_pre_rows = max(4L, min(6L, pre_weeks))
  )
  full_wide_raw[, tbr_y_raw := if (isTRUE(tbr_raw_fit$success)) tbr_raw_fit$pred else NA_real_]
  full_wide_raw[, synth_y_raw := if (isTRUE(use_tbr) && isTRUE(tbr_raw_fit$success)) tbr_y_raw else synthetic_control_y_raw]
  pre_fit <- full_wide[date__ >= e$pre_start & date__ <= e$pre_end]
  post_fit <- full_wide[date__ >= e$post_start & date__ <= e$post_end]
  post_fit_raw <- full_wide_raw[date__ >= e$post_start & date__ <= e$post_end]
  pre_fit[, complete_outcome_row__ := is.finite(qgt_num(get(treat_geo))) & is.finite(qgt_num(synth_y))]
  post_fit[, complete_outcome_row__ := is.finite(qgt_num(get(treat_geo))) & is.finite(qgt_num(synth_y))]
  pre_complete <- pre_fit[complete_outcome_row__ == TRUE]
  post_complete <- post_fit[complete_outcome_row__ == TRUE]
  if (nrow(pre_complete) < max(3L, min(6L, pre_weeks)) || !nrow(post_complete)) {
    return(qgt_event_not_estimable(event, "incomplete_synthetic_control_rows"))
  }
  incomplete_post_rows <- nrow(post_complete) < nrow(post_fit)
  pre_complete_dates <- pre_complete$date__
  post_complete_dates <- post_complete$date__
  pre_rmse <- sqrt(mean((pre_complete[[treat_geo]] - pre_complete$synth_y) ^ 2, na.rm = TRUE))
  pre_sd <- qgt_safe_sd(pre_complete[[treat_geo]], floor = 1e-8)
  pre_fit_score <- 1 - qgt_clip(pre_rmse / pre_sd, 0, 1)
  recent_n <- min(nrow(pre_complete), max(2L, floor(pre_weeks / 2)))
  recent_pre <- utils::tail(pre_complete, recent_n)
  recent_pre_rmse <- sqrt(mean((recent_pre[[treat_geo]] - recent_pre$synth_y) ^ 2, na.rm = TRUE))
  recent_pre_sd <- qgt_safe_sd(recent_pre[[treat_geo]], floor = 1e-8)
  recent_pre_fit_score <- 1 - qgt_clip(recent_pre_rmse / recent_pre_sd, 0, 1)
  lookback_sensitivity_score <- if (is.finite(pre_fit_score) && is.finite(recent_pre_fit_score)) {
    qgt_clip(1 - abs(pre_fit_score - recent_pre_fit_score), 0, 1)
  } else {
    NA_real_
  }
  scaled_l2_imbalance <- sqrt(sum((qgt_num(pre_complete[[treat_geo]]) - qgt_num(pre_complete$synth_y)) ^ 2, na.rm = TRUE)) /
    pmax(sqrt(sum(qgt_num(pre_complete[[treat_geo]]) ^ 2, na.rm = TRUE)), 1e-8)
  pre_resid <- qgt_num(pre_complete[[treat_geo]]) - qgt_num(pre_complete$synth_y)
  post_resid <- qgt_num(post_complete[[treat_geo]]) - qgt_num(post_complete$synth_y)
  post_lift <- if (any(is.finite(post_resid))) sum(post_resid, na.rm = TRUE) else NA_real_
  estimate_lift_from_wide <- function(wide, placebo_treat, placebo_donors) {
    placebo_treat <- as.character(placebo_treat)[1]
    placebo_donors <- setdiff(as.character(placebo_donors), placebo_treat)
    placebo_donors <- placebo_donors[placebo_donors %in% names(wide)]
    if (!placebo_treat %in% names(wide) || length(placebo_donors) < 2L) return(NA_real_)
    pre_tmp <- wide[date__ >= e$pre_start & date__ <= e$pre_end]
    post_tmp <- wide[date__ >= e$post_start & date__ <= e$post_end]
    if (!nrow(pre_tmp) || !nrow(post_tmp)) return(NA_real_)
    w <- qgt_ridge_synth_weights(pre_tmp[[placebo_treat]], pre_tmp[, ..placebo_donors], lambda_grid = lambda_grid, simplex = TRUE)
    if (all(!is.finite(w))) return(NA_real_)
    names(w) <- placebo_donors
    keep <- names(w)[is.finite(w)]
    w <- w[keep]
    if (!length(w) || !is.finite(sum(w)) || abs(sum(w)) <= 1e-12) return(NA_real_)
    w <- w / sum(w)
    donor_pre_means_tmp <- vapply(keep, function(cc) mean(pre_tmp[[cc]], na.rm = TRUE), numeric(1))
    intercept_tmp <- mean(pre_tmp[[placebo_treat]], na.rm = TRUE) - sum(w * donor_pre_means_tmp, na.rm = TRUE)
    pred <- intercept_tmp + as.numeric(as.matrix(post_tmp[, ..keep]) %*% w)
    ok <- is.finite(qgt_num(post_tmp[[placebo_treat]])) & is.finite(pred)
    if (!any(ok)) return(NA_real_)
    sum(qgt_num(post_tmp[[placebo_treat]])[ok] - pred[ok], na.rm = TRUE)
  }
  loo_lifts <- if (length(donor_cols) >= 3L && is.finite(post_lift)) {
    vapply(donor_cols, function(drop_donor) {
      estimate_lift_from_wide(full_wide, treat_geo, setdiff(donor_cols, drop_donor))
    }, numeric(1))
  } else {
    numeric()
  }
  loo_lifts <- loo_lifts[is.finite(loo_lifts)]
  leave_one_donor_out_lift_sd <- if (length(loo_lifts) >= 2L) stats::sd(loo_lifts) else NA_real_
  leave_one_donor_out_lift_max_abs_delta <- if (length(loo_lifts) && is.finite(post_lift)) max(abs(loo_lifts - post_lift), na.rm = TRUE) else NA_real_
  leave_one_donor_out_stability_score <- if (is.finite(leave_one_donor_out_lift_max_abs_delta) && is.finite(post_lift)) {
    qgt_clip(1 - leave_one_donor_out_lift_max_abs_delta / pmax(abs(post_lift), 1e-8), 0, 1)
  } else {
    NA_real_
  }
  placebo_pool <- names(sort(weights, decreasing = TRUE))
  placebo_pool <- placebo_pool[placebo_pool %in% donor_cols]
  placebo_pool <- utils::head(placebo_pool, 12L)
  donor_placebo_lifts <- if (length(placebo_pool) >= 3L && is.finite(post_lift)) {
    vapply(placebo_pool, function(placebo_geo) {
      estimate_lift_from_wide(full_wide, placebo_geo, setdiff(donor_cols, placebo_geo))
    }, numeric(1))
  } else {
    numeric()
  }
  donor_placebo_lifts <- donor_placebo_lifts[is.finite(donor_placebo_lifts)]
  donor_placebo_p_value <- if (length(donor_placebo_lifts) && is.finite(post_lift)) {
    (1 + sum(abs(donor_placebo_lifts) >= abs(post_lift), na.rm = TRUE)) / (1 + length(donor_placebo_lifts))
  } else {
    NA_real_
  }
  donor_placebo_strength <- if (is.finite(donor_placebo_p_value)) qgt_clip(1 - donor_placebo_p_value, 0, 1) else NA_real_
  donor_placebo_lift_median <- if (length(donor_placebo_lifts)) stats::median(donor_placebo_lifts, na.rm = TRUE) else NA_real_
  donor_placebo_lift_max_abs <- if (length(donor_placebo_lifts)) max(abs(donor_placebo_lifts), na.rm = TRUE) else NA_real_
  raw_post <- post_fit_raw[date__ %in% post_complete_dates]
  raw_post_resid <- if (treat_geo %in% names(raw_post) && "synth_y_raw" %in% names(raw_post)) {
    qgt_num(raw_post[[treat_geo]]) - qgt_num(raw_post$synth_y_raw)
  } else {
    NA_real_
  }
  raw_post_lift <- if (any(is.finite(raw_post_resid))) sum(raw_post_resid, na.rm = TRUE) else NA_real_
  n_post_resid <- sum(is.finite(post_resid))
  pre_resid_sd <- qgt_safe_sd(pre_resid, floor = 1e-8)
  lift_se <- pre_resid_sd * sqrt(max(n_post_resid, 1L))
  lift_z <- if (is.finite(lift_se) && lift_se > 1e-8) post_lift / lift_se else NA_real_
  placebo_n <- min(sum(is.finite(pre_resid)), max(2L, as.integer(post_weeks)))
  placebo_lift <- if (placebo_n >= 2L) sum(utils::tail(pre_resid[is.finite(pre_resid)], placebo_n), na.rm = TRUE) else NA_real_
  placebo_lift_abs_ratio <- if (is.finite(placebo_lift) && is.finite(post_lift) && abs(post_lift) > 1e-8) {
    abs(placebo_lift) / abs(post_lift)
  } else {
    NA_real_
  }
  time_placebo_window_n <- min(max(2L, as.integer(post_weeks)), length(pre_resid))
  time_placebo_lifts <- if (time_placebo_window_n >= 2L && length(pre_resid) >= time_placebo_window_n) {
    starts <- seq_len(length(pre_resid) - time_placebo_window_n + 1L)
    vapply(starts, function(i) {
      z <- pre_resid[seq.int(i, i + time_placebo_window_n - 1L)]
      if (all(is.finite(z))) sum(z) else NA_real_
    }, numeric(1))
  } else {
    numeric()
  }
  time_placebo_lifts <- time_placebo_lifts[is.finite(time_placebo_lifts)]
  time_placebo_p_value <- if (length(time_placebo_lifts) && is.finite(post_lift)) {
    (1 + sum(abs(time_placebo_lifts) >= abs(post_lift))) / (1 + length(time_placebo_lifts))
  } else {
    NA_real_
  }
  time_placebo_strength <- if (is.finite(time_placebo_p_value)) qgt_clip(1 - time_placebo_p_value, 0, 1) else NA_real_
  time_placebo_lift_median <- if (length(time_placebo_lifts)) stats::median(time_placebo_lifts) else NA_real_
  time_placebo_lift_max_abs <- if (length(time_placebo_lifts)) max(abs(time_placebo_lifts)) else NA_real_
  time_placebo_false_positive_rate <- if (length(time_placebo_lifts) && is.finite(post_lift)) {
    mean(abs(time_placebo_lifts) >= abs(post_lift))
  } else {
    NA_real_
  }
  incremental_outcome_ci_low <- if (is.finite(lift_se)) post_lift - 1.96 * lift_se else NA_real_
  incremental_outcome_ci_high <- if (is.finite(lift_se)) post_lift + 1.96 * lift_se else NA_real_
  post_actual <- if (any(is.finite(post_complete[[treat_geo]]))) sum(post_complete[[treat_geo]], na.rm = TRUE) else NA_real_
  lift_pct <- if (is.finite(post_actual) && abs(post_actual) > 1e-8) post_lift / post_actual else NA_real_
  mde_lift_abs <- if (is.finite(lift_se)) (stats::qnorm(1 - mde_alpha / 2) + stats::qnorm(mde_power)) * lift_se else NA_real_
  mde_lift_pct <- if (is.finite(mde_lift_abs) && is.finite(post_actual) && abs(post_actual) > 1e-8) mde_lift_abs / abs(post_actual) else NA_real_
  observed_to_mde_ratio <- if (is.finite(mde_lift_abs) && mde_lift_abs > 1e-8) abs(post_lift) / mde_lift_abs else NA_real_

  tr <- dt[as.character(get(geo_col)) == treat_geo]
  post_n_aligned <- length(post_complete_dates)
  pre_media_mean <- tr[get(date_col) %in% pre_complete_dates, mean(pmax(qgt_num(get(med)), 0), na.rm = TRUE)]
  post_media_sum <- tr[get(date_col) %in% post_complete_dates, sum(pmax(qgt_num(get(med)), 0), na.rm = TRUE)]
  incremental_media <- post_media_sum - pre_media_mean * post_n_aligned
  incremental_spend <- NA_real_
  if (!is.null(spend_col) && spend_col %in% names(tr)) {
    pre_spend_mean <- tr[get(date_col) %in% pre_complete_dates, mean(pmax(qgt_num(get(spend_col)), 0), na.rm = TRUE)]
    post_spend_sum <- tr[get(date_col) %in% post_complete_dates, sum(pmax(qgt_num(get(spend_col)), 0), na.rm = TRUE)]
    incremental_spend <- post_spend_sum - pre_spend_mean * post_n_aligned
  }
  marginal_response <- if (is.finite(incremental_media) && abs(incremental_media) > 1e-8) post_lift / incremental_media else NA_real_
  mr_ci_vals <- if (is.finite(incremental_media) && abs(incremental_media) > 1e-8) {
    c(incremental_outcome_ci_low / incremental_media, incremental_outcome_ci_high / incremental_media)
  } else {
    c(NA_real_, NA_real_)
  }
  marginal_response_ci_low <- if (any(is.finite(mr_ci_vals))) min(mr_ci_vals, na.rm = TRUE) else NA_real_
  marginal_response_ci_high <- if (any(is.finite(mr_ci_vals))) max(mr_ci_vals, na.rm = TRUE) else NA_real_
  cost_per_incremental_outcome <- if (is.finite(incremental_spend) && is.finite(raw_post_lift) && abs(raw_post_lift) > 1e-8) incremental_spend / raw_post_lift else NA_real_
  roi_like <- if (is.finite(incremental_spend) && abs(incremental_spend) > 1e-8) raw_post_lift / incremental_spend else NA_real_

  other_cols <- setdiff(all_media_cols, med)
  if (is.null(all_raw_media_cols)) {
    raw_media_lookup <- stats::setNames(all_media_cols, all_media_cols)
  } else {
    raw_media_lookup <- all_raw_media_cols
    if (is.null(names(raw_media_lookup))) names(raw_media_lookup) <- all_media_cols[seq_along(raw_media_lookup)]
  }
  other_contam <- 0
  co_moving <- data.table(variable = character(), signed_pct_change = numeric(), abs_pct_change = numeric(), change_class = character(), same_direction = logical())
  if (length(other_cols)) {
    vals <- vapply(other_cols, function(cc) {
      raw_cc <- as.character(raw_media_lookup[cc])
      if (is.na(raw_cc) || !nzchar(raw_cc) || !raw_cc %in% names(tr)) raw_cc <- cc
      pre <- tr[get(date_col) >= e$pre_start & get(date_col) <= e$pre_end, mean(pmax(qgt_num(get(raw_cc)), 0), na.rm = TRUE)]
      post <- tr[get(date_col) >= e$post_start & get(date_col) <= e$post_end, mean(pmax(qgt_num(get(raw_cc)), 0), na.rm = TRUE)]
      other_materiality <- max(min_volume, 0.05 * qgt_positive_scale(tr[[raw_cc]], floor = min_volume))
      cls <- qgt_change_class(pre, post, other_media_contamination_pct, near_zero = min_volume, material = other_materiality)
      if (cls %in% c("turn_on", "turn_off")) Inf else if (is.finite(pre) && pre > 1e-8) abs((post - pre) / pre) else 0
    }, numeric(1))
    co_moving <- rbindlist(lapply(other_cols, function(cc) {
      raw_cc <- as.character(raw_media_lookup[cc])
      if (is.na(raw_cc) || !nzchar(raw_cc) || !raw_cc %in% names(tr)) raw_cc <- cc
      pre <- tr[get(date_col) >= e$pre_start & get(date_col) <= e$pre_end, mean(pmax(qgt_num(get(raw_cc)), 0), na.rm = TRUE)]
      post <- tr[get(date_col) >= e$post_start & get(date_col) <= e$post_end, mean(pmax(qgt_num(get(raw_cc)), 0), na.rm = TRUE)]
      other_materiality <- max(min_volume, 0.05 * qgt_positive_scale(tr[[raw_cc]], floor = min_volume))
      cls <- qgt_change_class(pre, post, other_media_contamination_pct, near_zero = min_volume, material = other_materiality)
      signed <- if (cls == "turn_on") Inf else if (cls == "turn_off") -Inf else if (is.finite(pre) && pre > 1e-8) (post - pre) / pre else NA_real_
      abs_signed <- if (cls %in% c("turn_on", "turn_off")) Inf else abs(signed)
      same_dir <- (is.infinite(signed) || is.finite(signed)) && is.finite(incremental_media) &&
        sign(signed) == sign(incremental_media)
      data.table(
        variable = cc,
        signed_pct_change = signed,
        abs_pct_change = abs_signed,
        change_class = cls,
        same_direction = same_dir
      )
    }), use.names = TRUE, fill = TRUE)
    other_contam <- if (any(!is.finite(vals) & !is.na(vals))) Inf else max(vals[is.finite(vals)], 0, na.rm = TRUE)
  }
  holiday_contam <- 0
  if (length(control_cols)) {
    vals <- vapply(control_cols[control_cols %in% names(tr)], function(cc) {
      mean(abs(qgt_num(tr[get(date_col) >= e$post_start & get(date_col) <= e$post_end, get(cc)])), na.rm = TRUE)
    }, numeric(1))
    holiday_contam <- max(vals[is.finite(vals)], 0, na.rm = TRUE)
  }
  donor_weight_vec <- weights[is.finite(weights) & weights > 0]
  donor_weight_sum <- sum(donor_weight_vec, na.rm = TRUE)
  if (is.finite(donor_weight_sum) && donor_weight_sum > 1e-12) donor_weight_vec <- donor_weight_vec / donor_weight_sum
  donor_concentration <- if (length(donor_weight_vec)) max(donor_weight_vec, na.rm = TRUE) else NA_real_
  donor_weight_hhi <- if (length(donor_weight_vec)) sum(donor_weight_vec ^ 2, na.rm = TRUE) else NA_real_
  donor_effective_n <- if (is.finite(donor_weight_hhi) && donor_weight_hhi > 1e-12) 1 / donor_weight_hhi else NA_real_
  donor_dominant_flag <- is.finite(donor_concentration) && donor_concentration >= 0.70
  donor_shortage_penalty <- if (length(donor_cols) < min_donors) 1 else 0
  donor_contam_penalty <- if (isTRUE(donor_contamination_flag) || is.infinite(donor_contamination_max)) 1 else qgt_clip(donor_contamination_max / donor_contamination_pct, 0, 1)
  pre_period_placebo_penalty <- if (is.finite(placebo_lift_abs_ratio)) qgt_clip(placebo_lift_abs_ratio, 0, 1) else 0.5
  donor_placebo_penalty <- if (is.finite(donor_placebo_p_value)) qgt_clip((donor_placebo_p_value - 0.10) / 0.40, 0, 1) else 0.5
  time_placebo_penalty <- if (is.finite(time_placebo_p_value)) qgt_clip((time_placebo_p_value - 0.10) / 0.40, 0, 1) else 0.5
  placebo_penalty <- max(pre_period_placebo_penalty, donor_placebo_penalty, time_placebo_penalty, na.rm = TRUE)
  signal_score <- if (is.finite(lift_z)) qgt_clip((abs(lift_z) - 0.5) / 2.0, 0, 1) else 0.25
  direction_consistency_score <- if (is.finite(marginal_response)) {
    if (marginal_response > 0) 1 else if (marginal_response < 0) 0.15 else 0.50
  } else {
    0.25
  }
  power_score <- if (is.finite(observed_to_mde_ratio)) qgt_clip(observed_to_mde_ratio, 0, 1) else 0.25
  other_contam_penalty <- if (is.infinite(other_contam)) 1 else qgt_clip(other_contam / other_media_contamination_pct, 0, 1)
  contamination_score <- qgt_clip(0.45 * other_contam_penalty +
                                    0.20 * donor_contam_penalty +
                                    0.25 * qgt_clip(holiday_contam, 0, 1) +
                                    0.10 * qgt_clip(donor_concentration - 0.50, 0, 0.50) / 0.50, 0, 1)
  lookback_quality <- if (is.finite(lookback_sensitivity_score)) lookback_sensitivity_score else 0.50
  quality_score <- qgt_clip(0.45 * pre_fit_score + 0.20 * qgt_clip(length(donor_cols) / 8, 0, 1) +
                              0.15 * (1 - contamination_score) + 0.10 * (1 - placebo_penalty) +
                              0.05 * signal_score + 0.03 * (1 - donor_shortage_penalty) +
                              0.02 * lookback_quality, 0, 1)
  evidence_score <- 100 * qgt_clip(
    0.34 * quality_score +
      0.18 * signal_score +
      0.14 * power_score +
      0.14 * direction_consistency_score +
      0.10 * (1 - contamination_score) +
      0.10 * (1 - placebo_penalty),
    0, 1
  )
  evidence_tier <- qgt_evidence_tier_from_score(evidence_score)
  diagnostic_parts <- c()
  if (length(donor_cols) < min_donors) diagnostic_parts <- c(diagnostic_parts, "few_donors")
  if (isTRUE(donor_contamination_flag)) diagnostic_parts <- c(diagnostic_parts, "donor_media_contamination")
  if (isTRUE(no_unaffected_donor_geos)) diagnostic_parts <- c(diagnostic_parts, "no_unaffected_donor_geos_same_channel")
  if (!isTRUE(no_unaffected_donor_geos) && unaffected_donor_n < min_donors) diagnostic_parts <- c(diagnostic_parts, "few_clean_donor_geos_same_channel")
  if (any(contamination$donor_change_class == "turn_on", na.rm = TRUE)) diagnostic_parts <- c(diagnostic_parts, "donor_turn_on")
  if (any(contamination$donor_change_class == "turn_off", na.rm = TRUE)) diagnostic_parts <- c(diagnostic_parts, "donor_turn_off")
  if ((is.finite(other_contam) && other_contam >= other_media_contamination_pct) || is.infinite(other_contam)) diagnostic_parts <- c(diagnostic_parts, "other_media_moved")
  if (nrow(co_moving) && any(co_moving$change_class == "turn_on", na.rm = TRUE)) diagnostic_parts <- c(diagnostic_parts, "other_media_turn_on")
  if (nrow(co_moving) && any(co_moving$change_class == "turn_off", na.rm = TRUE)) diagnostic_parts <- c(diagnostic_parts, "other_media_turn_off")
  if (is.finite(pre_fit_score) && pre_fit_score < 0.50) diagnostic_parts <- c(diagnostic_parts, "weak_pre_fit")
  if (!isTRUE(synth_available)) diagnostic_parts <- c(diagnostic_parts, "synthetic_control_weights_failed")
  if (!identical(selected_counterfactual_method, "ridge_synthetic_control")) {
    diagnostic_parts <- c(diagnostic_parts, paste0(selected_counterfactual_method, "_counterfactual"))
  }
  if (is.finite(lookback_sensitivity_score) && lookback_sensitivity_score < 0.70) diagnostic_parts <- c(diagnostic_parts, "lookback_sensitive_pre_fit")
  if (is.finite(placebo_lift_abs_ratio) && placebo_lift_abs_ratio > 0.50) diagnostic_parts <- c(diagnostic_parts, "large_pre_period_placebo_lift")
  if (is.finite(donor_placebo_p_value) && donor_placebo_p_value >= 0.25) diagnostic_parts <- c(diagnostic_parts, "donor_placebo_false_positive_risk")
  if (is.finite(time_placebo_p_value) && time_placebo_p_value >= 0.25) diagnostic_parts <- c(diagnostic_parts, "time_placebo_false_positive_risk")
  if (is.finite(leave_one_donor_out_stability_score) && leave_one_donor_out_stability_score < 0.50) diagnostic_parts <- c(diagnostic_parts, "donor_leave_one_out_sensitive")
  if (isTRUE(donor_dominant_flag)) diagnostic_parts <- c(diagnostic_parts, "dominant_donor_weight")
  if (is.finite(lift_z) && abs(lift_z) < 1.00) diagnostic_parts <- c(diagnostic_parts, "weak_lift_signal")
  if (is.finite(marginal_response) && marginal_response < 0) diagnostic_parts <- c(diagnostic_parts, "effect_direction_opposes_media")
  if (nrow(co_moving) && any(co_moving$abs_pct_change >= other_media_contamination_pct, na.rm = TRUE)) diagnostic_parts <- c(diagnostic_parts, "co_moving_media_signal")
  if (isTRUE(incomplete_post_rows)) diagnostic_parts <- c(diagnostic_parts, "incomplete_post_synthetic_rows")
  if (!any(is.finite(raw_post_resid))) diagnostic_parts <- c(diagnostic_parts, "raw_synthetic_lift_unavailable")
  if (!length(diagnostic_parts)) diagnostic_parts <- "estimated"
  co_moving_hits <- co_moving[(is.finite(abs_pct_change) & abs_pct_change >= other_media_contamination_pct) | change_class %in% c("turn_on", "turn_off")]
  co_moving_same_direction_n <- if (nrow(co_moving_hits)) sum(co_moving_hits$same_direction %in% TRUE, na.rm = TRUE) else 0L
  co_moving_opposite_direction_n <- if (nrow(co_moving_hits)) sum(!(co_moving_hits$same_direction %in% TRUE), na.rm = TRUE) else 0L
  bundle_direction_consistent <- nrow(co_moving_hits) == 0L || co_moving_opposite_direction_n == 0L
  if (nrow(co_moving_hits) && !isTRUE(bundle_direction_consistent)) diagnostic_parts <- c(diagnostic_parts, "opposite_direction_co_moving_media")
  co_moving_summary <- if (nrow(co_moving_hits)) {
    paste(paste0(co_moving_hits$variable, ":", signif(co_moving_hits$signed_pct_change, 3)), collapse = "|")
  } else {
    ""
  }
  incremental_for_col <- function(cc) {
    if (!cc %in% names(tr)) return(NA_real_)
    pre_mean <- tr[get(date_col) %in% pre_complete_dates, mean(pmax(qgt_num(get(cc)), 0), na.rm = TRUE)]
    post_sum <- tr[get(date_col) %in% post_complete_dates, sum(pmax(qgt_num(get(cc)), 0), na.rm = TRUE)]
    post_sum - pre_mean * post_n_aligned
  }
  moved_media_cols <- sort(unique(c(med, co_moving_hits$variable)))
  bundle_incremental_support_val <- if (length(moved_media_cols) > 1L) {
    vals <- vapply(moved_media_cols, incremental_for_col, numeric(1))
    if (any(is.finite(vals))) sum(vals, na.rm = TRUE) else NA_real_
  } else {
    NA_real_
  }
  if (is.null(all_spend_cols)) {
    spend_lookup <- stats::setNames(all_media_cols, all_media_cols)
  } else {
    spend_lookup <- all_spend_cols
    if (is.null(names(spend_lookup))) names(spend_lookup) <- all_media_cols[seq_along(spend_lookup)]
  }
  moved_spend_cols <- unique(as.character(spend_lookup[moved_media_cols]))
  moved_spend_cols <- moved_spend_cols[!is.na(moved_spend_cols) & nzchar(moved_spend_cols) & moved_spend_cols %in% names(tr)]
  bundle_incremental_spend_val <- if (length(moved_media_cols) > 1L && length(moved_spend_cols)) {
    vals <- vapply(moved_spend_cols, incremental_for_col, numeric(1))
    if (any(is.finite(vals))) sum(vals, na.rm = TRUE) else NA_real_
  } else {
    NA_real_
  }
  bundle_incremental_outcome_val <- if (length(moved_media_cols) > 1L) raw_post_lift else NA_real_
  bundle_return_prior_val <- if (is.finite(bundle_incremental_spend_val) && abs(bundle_incremental_spend_val) > 1e-8) {
    bundle_incremental_outcome_val / bundle_incremental_spend_val
  } else {
    NA_real_
  }
  bundle_cost_per_outcome_val <- if (is.finite(bundle_incremental_spend_val) && is.finite(bundle_incremental_outcome_val) && abs(bundle_incremental_outcome_val) > 1e-8) {
    bundle_incremental_spend_val / bundle_incremental_outcome_val
  } else {
    NA_real_
  }
  effect_direction <- if (is.finite(marginal_response) && marginal_response > 0) {
    "positive_media_effect"
  } else if (is.finite(marginal_response) && marginal_response < 0) {
    "negative_or_confounded_media_effect"
  } else {
    "inconclusive"
  }

  data.table(
    event_id = e$event_id,
    variable = e$variable,
    geo = treat_geo,
    event_start = e$event_start,
    event_end = e$event_end,
    starting_support = e$starting_support,
    event_media = qgt_event_value(e, "event_media", NA_real_),
    signed_treatment_intensity = qgt_event_value(e, "signed_treatment_intensity", NA_real_),
    abs_change = qgt_event_value(e, "abs_change", qgt_event_value(e, "change_abs", NA_real_)),
    change_abs = qgt_event_value(e, "change_abs", qgt_event_value(e, "abs_change", NA_real_)),
    pct_change = e$pct_change,
    pct_change_abs = qgt_event_value(e, "pct_change_abs", abs(e$pct_change)),
    robust_z = e$robust_z,
    ramp_direction = qgt_event_value(e, "ramp_direction", qgt_direction_from_signed_change(qgt_event_value(e, "signed_treatment_intensity", NA_real_))),
    event_type = qgt_event_value(e, "event_type", qgt_direction_from_signed_change(qgt_event_value(e, "signed_treatment_intensity", NA_real_))),
    media_cutoff_flag = qgt_event_value(e, "media_cutoff_flag", FALSE),
    donor_n = length(donor_cols),
    clean_donor_geo_n = unaffected_donor_n,
    donor_contaminated_geo_n = donor_contaminated_geo_n,
    donor_weight_max = donor_concentration,
    donor_weight_hhi = donor_weight_hhi,
    donor_effective_n = donor_effective_n,
    donor_dominant_flag = donor_dominant_flag,
    scaled_l2_imbalance = scaled_l2_imbalance,
    pre_fit_score = pre_fit_score,
    recent_pre_fit_score = recent_pre_fit_score,
    lookback_sensitivity_score = lookback_sensitivity_score,
    contamination_score = contamination_score,
    signal_score = signal_score,
    direction_consistency_score = direction_consistency_score,
    power_score = power_score,
    evidence_score = evidence_score,
    quality_score = quality_score,
    evidence_tier = evidence_tier,
    diagnostic_reason = paste(unique(diagnostic_parts), collapse = "|"),
    placebo_lift = placebo_lift,
    placebo_lift_abs_ratio = placebo_lift_abs_ratio,
    donor_placebo_p_value = donor_placebo_p_value,
    donor_placebo_strength = donor_placebo_strength,
    donor_placebo_lift_median = donor_placebo_lift_median,
    donor_placebo_lift_max_abs = donor_placebo_lift_max_abs,
    time_placebo_n = length(time_placebo_lifts),
    time_placebo_p_value = time_placebo_p_value,
    time_placebo_strength = time_placebo_strength,
    time_placebo_lift_median = time_placebo_lift_median,
    time_placebo_lift_max_abs = time_placebo_lift_max_abs,
    time_placebo_false_positive_rate = time_placebo_false_positive_rate,
    leave_one_donor_out_lift_sd = leave_one_donor_out_lift_sd,
    leave_one_donor_out_lift_max_abs_delta = leave_one_donor_out_lift_max_abs_delta,
    leave_one_donor_out_stability_score = leave_one_donor_out_stability_score,
    selected_counterfactual_method = selected_counterfactual_method,
    ridge_lambda = ridge_lambda,
    ridge_lambda_cv_rmse = ridge_lambda_cv_rmse,
    ridge_lambda_selection_method = ridge_lambda_selection_method,
    ridge_lambda_cv_fold_n = as.integer(ridge_lambda_cv_fold_n),
    ridge_retained_donor_n = as.integer(ridge_retained_donor_n),
    ridge_dropped_zero_variance_donor_n = as.integer(ridge_dropped_zero_variance_donor_n),
    counterfactual_fallback_reason = counterfactual_fallback_reason,
    synthetic_control_pre_fit_score = synthetic_control_pre_fit_score,
    tbr_pre_fit_score = tbr_fit$pre_fit_score,
    tbr_incremental_outcome = if (isTRUE(tbr_fit$success) && identical(tbr_fit$method, "time_based_regression")) tbr_fit$lift else NA_real_,
    tbr_incremental_outcome_raw = if (isTRUE(tbr_raw_fit$success) && identical(tbr_raw_fit$method, "time_based_regression")) tbr_raw_fit$lift else NA_real_,
    tbr_lift_z = if (isTRUE(tbr_fit$success) && identical(tbr_fit$method, "time_based_regression")) tbr_fit$lift_z else NA_real_,
    did_incremental_outcome = if (isTRUE(tbr_fit$success) && identical(tbr_fit$method, "difference_in_differences")) tbr_fit$lift else NA_real_,
    did_incremental_outcome_raw = if (isTRUE(tbr_raw_fit$success) && identical(tbr_raw_fit$method, "difference_in_differences")) tbr_raw_fit$lift else NA_real_,
    lift_se = lift_se,
    lift_z = lift_z,
    pre_outcome_row_n = nrow(pre_fit),
    pre_complete_row_n = nrow(pre_complete),
    post_outcome_row_n = nrow(post_fit),
    post_complete_row_n = nrow(post_complete),
    incremental_outcome_ci_low = incremental_outcome_ci_low,
    incremental_outcome_ci_high = incremental_outcome_ci_high,
    incremental_outcome = post_lift,
    incremental_outcome_raw = raw_post_lift,
    incremental_media = incremental_media,
    incremental_spend = incremental_spend,
    contribution = post_lift,
    contribution_raw = raw_post_lift,
    contribution_pct = lift_pct,
    marginal_response = marginal_response,
    cost_per_incremental_outcome = cost_per_incremental_outcome,
    roi_like = roi_like,
    marginal_response_ci_low = marginal_response_ci_low,
    marginal_response_ci_high = marginal_response_ci_high,
    mde_lift_abs = mde_lift_abs,
    mde_lift_pct = mde_lift_pct,
    observed_to_mde_ratio = observed_to_mde_ratio,
    lift_pct = lift_pct,
    effect_direction = effect_direction,
    co_moving_channel_n = nrow(co_moving_hits),
    co_moving_same_direction_n = co_moving_same_direction_n,
    co_moving_opposite_direction_n = co_moving_opposite_direction_n,
    bundle_direction_consistent = bundle_direction_consistent,
    co_moving_channel_list = paste(sort(unique(co_moving_hits$variable)), collapse = "|"),
    co_moving_media_summary = co_moving_summary,
    overlap_event_n = NA_integer_,
    same_geo_overlap_event_n = NA_integer_,
    overlap_contamination_score = NA_real_,
    synth_intercept = synth_intercept,
    raw_synth_intercept = raw_synth_intercept,
    bundle_incremental_support = bundle_incremental_support_val,
    bundle_incremental_outcome_raw = bundle_incremental_outcome_val,
    bundle_incremental_spend_raw = bundle_incremental_spend_val,
    bundle_return_prior_raw = bundle_return_prior_val,
    bundle_cost_per_outcome_raw = bundle_cost_per_outcome_val,
    counterfactual_method = selected_counterfactual_method,
    donor_geos = paste(donor_cols, collapse = "|"),
    donor_weights = paste(paste0(donor_cols, ":", signif(weights, 4)), collapse = "|")
  )
}
